    // Step 1: Frequency Counting
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    const getMirror = (c) => {
        const code = c.charCodeAt(0);

        // Check if it's a lowercase letter ('a' = 97, 'z' = 122)
        if (code >= 97 && code <= 122) {
            const base = 'a'.charCodeAt(0);
            // Position p (0 for 'a', 25 for 'z')
            const p = code - base;
            // Mirror position p' = 25 - p
            const p_prime = 25 - p;
            return String.fromCharCode(base + p_prime);
        } 
        // Check if it's a digit ('0' = 48, '9' = 57)
        else if (code >= 48 && code <= 57) {
            const base = '0'.charCodeAt(0);
            // Position p (0 for '0', 9 for '9')
            const p = code - base;
            // Mirror position p' = 9 - p
            const p_prime = 9 - p;
            return String.fromCharCode(base + p_prime);
        }
        // Should not happen based on problem constraints
        return null; 
    };

    let totalDifference = 0;
    const processed = new Set();

    // Get unique characters present in s
    const uniqueChars = Array.from(new Set(s));

    // Step 3: Iterating and Summing
    for (const c of uniqueChars) {
        if (processed.has(c)) {
            continue;
        }

        const m = getMirror(c);

        // If the mirror is null (shouldn't happen), skip.
        if (!m) continue;

        // Calculate frequencies. If a character is not in s, its frequency is 0.
        const freqC = freq.get(c) || 0;
        const freqM = freq.get(m) || 0;

        // Calculate the absolute difference
        const diff = Math.abs(freqC - freqM);

        totalDifference += diff;

        // Mark both c and its mirror m as processed to avoid double counting
        processed.add(c);
        processed.add(m);
    }

    return totalDifference;
}

